import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import { H2, H4 } from "@blueprintjs/core";
import { observer } from "mobx-react";

export const Client: FunctionComponent = observer(() => {
  return (
    <div>
      <H2>
        Welcome to Heabank ! Bienvenue {ctx.store.getName()}, vous êtes client
        chez Heabank !
      </H2>
      <H4>
        Hello dear customer, to finalize your registration, please fill in the
        various fields below. A banker will then be in charge of your file in
        order to process your registration request. You will be able to
        reconnect whenever you want to follow the status of your application.
      </H4>
    </div>
  );
});
